(function(){'use strict';
var doc=document,win=window;

/* ─── Hero Carousel ─── */
(function(){
  var items=doc.querySelectorAll('.image-carousel__item');
  if(!items.length)return;
  var current=0,len=items.length;
  function next(){
    var prev=items[current];
    current=(current+1)%len;
    prev.classList.add('fade--out');
    prev.style.zIndex=1;
    items[current].classList.remove('fade--out');
    items[current].style.zIndex=3;
    for(var i=0;i<len;i++){
      if(i!==current&&i!==(current+len-1)%len){
        items[i].style.zIndex=1;
      }
    }
  }
  for(var i=1;i<len;i++){items[i].classList.add('fade--out');items[i].style.zIndex=1;}
  items[0].style.zIndex=3;
  setInterval(next,6000);
})();

/* ─── Scroll Header Shadow ─── */
(function(){
  var header=doc.querySelector('.site-header');
  if(!header)return;
  var ticking=false;
  function check(){
    header.classList.toggle('has--shadow',win.scrollY>10);
    ticking=false;
  }
  win.addEventListener('scroll',function(){
    if(!ticking){requestAnimationFrame(check);ticking=true;}
  },{passive:true});
  check();
})();

/* ─── Search Popup ─── */
(function(){
  var toggles=doc.querySelectorAll('.site-search-open');
  if(!toggles.length)return;
  var wrapper=toggles[0].closest('.site-search--wrapper')||doc.querySelector('.site-search');
  toggles.forEach(function(el){
    el.addEventListener('click',function(e){
      e.preventDefault();
      doc.body.classList.toggle('open--site-search');
      if(doc.body.classList.contains('open--site-search')){
        setTimeout(function(){
          var inp=doc.querySelector('.site-search__input');
          if(inp)inp.focus();
        },200);
      }
    });
  });
  doc.addEventListener('click',function(e){
    if(doc.body.classList.contains('open--site-search')){
      var content=doc.querySelector('.site-search__content');
      if(content&&!content.contains(e.target)&&!e.target.closest('.site-search-open')){
        doc.body.classList.remove('open--site-search');
      }
    }
  });
})();

/* ─── Mobile Navigation ─── */
(function(){
  var openBtns=doc.querySelectorAll('.navigation-mobile__open, .navigation-scroll__open');
  if(!openBtns.length)return;
  openBtns.forEach(function(btn){
    btn.addEventListener('click',function(e){
      e.preventDefault();
      doc.body.classList.toggle('open--navigation-mobile');
    });
  });
  var overlay=doc.createElement('div');
  overlay.className='navigation-overlay';
  overlay.addEventListener('click',function(){
    doc.body.classList.remove('open--navigation-mobile');
  });
  doc.body.appendChild(overlay);
})();

/* ─── Cookie Bar ─── */
(function(){
  var closeBtn=doc.querySelector('.cookie-bar__close');
  if(closeBtn){
    closeBtn.addEventListener('click',function(e){
      e.preventDefault();
      doc.querySelector('.cookie-bar').style.display='none';
      try{localStorage.setItem('cookie_bar','closed');}catch(e){}
    });
    if(localStorage.getItem('cookie_bar')==='closed'){
      doc.querySelector('.cookie-bar').style.display='none';
    }
  }
})();

/* ─── Online Banking ─── */
(function(){
  var ob=doc.querySelector('.header-online-banking');
  if(!ob)return;
  var loginForm=ob.querySelector('.header-online-banking__login-form');
  if(!loginForm){
    var dd=doc.querySelector('.header-online-banking__login-form');
    if(!dd){
      var clone=doc.querySelector('.page-heading .header-online-banking__login-form');
      if(clone){
        var newForm=clone.cloneNode(true);
        newForm.classList.remove('header-online-banking__login-form');
        newForm.style.cssText='display:block;position:static;box-shadow:none;padding:2rem 0';
        ob.appendChild(newForm);
      }
    }
  }
})();

/* ─── Responsive helper ─── */
(function(){
  var span=doc.querySelector('.responsive');
  if(!span)return;
  var nav=doc.querySelector('.navigation-main');
  var scrollMenu=doc.querySelector('.scroll-menu');
  function resize(){
    var show=win.getComputedStyle(span).getPropertyValue('display');
    var isMobile=show==='block';
    if(nav)nav.style.display=isMobile?'none':'';
    if(scrollMenu)scrollMenu.style.display=isMobile?'':'none';
  }
  win.addEventListener('resize',resize);
  resize();
})();

/* ─── Accordion (for other pages) ─── */
(function(){
  var items=doc.querySelectorAll('.accordion__title');
  items.forEach(function(title){
    title.addEventListener('click',function(e){
      e.preventDefault();
      var item=this.closest('.accordion__item');
      if(item)item.classList.toggle('active');
    });
  });
})();

})();
